public class WizardData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public ExperienceInfo Experience { get; set; } = new();
    public ReferencesInfo References { get; set; } = new();

    public bool IsStepCompleted(int step) => step switch
    {
        1 => !string.IsNullOrWhiteSpace(PersonalInfo.Name)
             && !string.IsNullOrWhiteSpace(PersonalInfo.Email),
        2 => Experience.Jobs.Count > 0,
        3 => References.Contacts.Count > 0,
        _ => false
    };
