using System.Collections.Concurrent;
using sv_de5049dec736493688b7298d951eb750.Models;

namespace sv_de5049dec736493688b7298d951eb750.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by a session identifier.
/// In per-page interactive server mode each navigation tears down the circuit,
/// so a scoped service would lose state. A singleton with a per-user key
/// survives across navigations while keeping each user's data isolated.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

