namespace sv_de5049dec736493688b7298d951eb750.Services;

/// <summary>
/// Reads or creates a cookie-based session identifier so the singleton
/// WizardStateService can key data per-user. Works in both static SSR
/// (layout) and interactive server (pages) via IHttpContextAccessor.
/// </summary>
public static class WizardSessionHelper
{
    private const string CookieName = "WizardSessionId";

    public static string GetOrCreateSessionId(IHttpContextAccessor httpContextAccessor)
    {
        var context = httpContextAccessor.HttpContext;
        if (context is null)
            return Guid.NewGuid().ToString();

        if (context.Request.Cookies.TryGetValue(CookieName, out var existing)
            && !string.IsNullOrWhiteSpace(existing))
        {
            return existing;
        }

        var newId = Guid.NewGuid().ToString();
        context.Response.Cookies.Append(CookieName, newId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
        return newId;
    }
}

