arguments.new_str:
@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_de5049dec736493688b7298d951eb750.Services.WizardStateService WizardState
@using sv_de5049dec736493688b7298d951eb750.Services

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (CurrentStep > 0)
            {
                <nav class="wizard-progress" aria-label="Application progress">
                    @for (int i = 1; i <= TotalSteps; i++)
                    {
                        var step = i;
                        var isCurrent = step == CurrentStep;
                        var isCompleted = _wizardData?.IsStepCompleted(step) == true;
                        <a href="@StepUrl(step)"
                           class="wizard-step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "")"
                           aria-current="@(isCurrent ? "step" : null)">
                            <span class="step-number">@step</span>
                            <span class="step-label">@StepLabel(step)</span>
                        </a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private const int TotalSteps = 4;
    private sv_de5049dec736493688b7298d951eb750.Models.WizardData? _wizardData;

    private int CurrentStep
    {
        get
        {
            var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
            return path switch
            {
                "/apply/personal-info" => 1,
                "/apply/experience" => 2,
                "/apply/references" => 3,
                "/apply/review" => 4,
                _ => 0
            };
        }
    }

    protected override void OnInitialized()
    {
        if (CurrentStep > 0)
        {
            var sessionId = WizardSessionHelper.GetOrCreateSessionId(HttpContextAccessor);
            _wizardData = WizardState.GetOrCreate(sessionId);
        }
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

