@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_de5049dec736493688b7298d951eb750.Services.WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_de5049dec736493688b7298d951eb750.Models
@using sv_de5049dec736493688b7298d951eb750.Services

<PageTitle>Step 1: Personal Info</PageTitle>
<h1>Personal Information</h1>

<EditForm Model="_model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private PersonalInfo _model = new();

    protected override void OnInitialized()
    {
        var sessionId = WizardSessionHelper.GetOrCreateSessionId(HttpContextAccessor);
        var data = WizardState.GetOrCreate(sessionId);
        _model = data.PersonalInfo;
    }

    private void Next()
    {
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_de5049dec736493688b7298d951eb750.Services.WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_de5049dec736493688b7298d951eb750.Models
@using sv_de5049dec736493688b7298d951eb750.Services

<PageTitle>Step 2: Experience</PageTitle>
<h1>Work Experience</h1>

<div class="mb-3">
    <h5>Add a Job</h5>
    <div class="row g-2 mb-2">
        <div class="col">
            <input class="form-control" placeholder="Company" @bind="_newJob.Company" />
        </div>
        <div class="col">
            <input class="form-control" placeholder="Title" @bind="_newJob.Title" />
